import os
import logging
from typing import Dict, List, Optional, Union, Tuple
from datetime import datetime, timedelta
from decimal import Decimal, ROUND_HALF_UP
import shopify

class PricingEngine:
    """
    Pricing engine for dynamic pricing management with support for bulk operations,
    competitive pricing, promotional pricing, and automated price optimization.
    """

    def __init__(self):
        self.logger = logging.getLogger(__name__)

    def update_product_price(self, product_id: int, new_price: Union[str, float, Decimal], 
                           variant_id: Optional[int] = None, 
                           compare_at_price: Optional[Union[str, float, Decimal]] = None) -> Dict:
        """
        Update price for a specific product or variant.

        Args:
            product_id: Shopify product ID
            new_price: New price to set
            variant_id: Optional variant ID, if None updates first variant
            compare_at_price: Optional compare-at price for sale display

        Returns:
            Dict with update status and details
        """
        try:
            product = shopify.Product.find(product_id)
            if not product:
                return {"success": False, "error": f"Product {product_id} not found"}

            # Convert price to proper decimal format
            formatted_price = self._format_price(new_price)
            formatted_compare_price = self._format_price(compare_at_price) if compare_at_price else None

            if variant_id:
                variant = next((v for v in product.variants if v.id == variant_id), None)
                if not variant:
                    return {"success": False, "error": f"Variant {variant_id} not found"}
                target_variant = variant
            else:
                target_variant = product.variants[0] if product.variants else None
                if not target_variant:
                    return {"success": False, "error": "No variants found for product"}

            old_price = target_variant.price
            target_variant.price = formatted_price

            if formatted_compare_price:
                target_variant.compare_at_price = formatted_compare_price

            if product.save():
                self.logger.info(f"Updated price for product {product_id}, variant {target_variant.id}: "
                               f"{old_price} -> {formatted_price}")

                return {
                    "success": True,
                    "product_id": product_id,
                    "variant_id": target_variant.id,
                    "old_price": str(old_price),
                    "new_price": str(formatted_price),
                    "compare_at_price": str(formatted_compare_price) if formatted_compare_price else None
                }
            else:
                return {"success": False, "error": f"Failed to save product: {product.errors.full_messages()}"}

        except Exception as e:
            self.logger.error(f"Error updating product price: {str(e)}")
            return {"success": False, "error": str(e)}

    def bulk_price_update(self, price_updates: List[Dict]) -> Dict:
        """
        Perform bulk price updates for multiple products.

        Args:
            price_updates: List of dicts with keys: product_id, price, variant_id (optional), compare_at_price (optional)

        Returns:
            Dict with bulk update results
        """
        try:
            results = []
            successful_updates = 0
            failed_updates = 0

            for update in price_updates:
                result = self.update_product_price(
                    product_id=update['product_id'],
                    new_price=update['price'],
                    variant_id=update.get('variant_id'),
                    compare_at_price=update.get('compare_at_price')
                )

                if result['success']:
                    successful_updates += 1
                else:
                    failed_updates += 1

                results.append(result)

            self.logger.info(f"Bulk price update completed: {successful_updates} successful, {failed_updates} failed")

            return {
                "success": True,
                "total_processed": len(price_updates),
                "successful_updates": successful_updates,
                "failed_updates": failed_updates,
                "results": results
            }

        except Exception as e:
            self.logger.error(f"Error in bulk price update: {str(e)}")
            return {"success": False, "error": str(e)}

